patch:
--- linux-2.6/include/net/ip6_fib.h.orig	2007-05-08 01:10:35.000000000 +0200
+++ linux-2.6/include/net/ip6_fib.h	2007-05-08 01:10:59.000000000 +0200
@@ -109,6 +109,9 @@ struct rt6_info

 static inline struct inet6_dev *ip6_dst_idev(struct dst_entry *dst)
 {
+	if (!dst)
+		return NULL;
+
 	return ((struct rt6_info *)dst)->rt6i_idev;
 }
